const matches = [];
const seenIds = new Set();

function safeEmail() {
  try {
    return $('Set Email Input').first().json.emailToCheck.toLowerCase();
  } catch(e) {
    return '';
  }
}

const email = safeEmail();

function addMatch(obj) {
  if (!obj || !obj.id) return;
  if (seenIds.has(obj.id)) return;
  seenIds.add(obj.id);
  matches.push(obj);
}

// ─────────────────────────────────────────────
// USERS — covers all user-based account types:
// Active, Shared Mailbox, Room, Equipment,
// Guest, Hybrid, Disabled, Licensed/Unlicensed
// ─────────────────────────────────────────────
function safeGet(nodeName) {
  try {
    const items = $(nodeName).all();
    if (!items || items.length === 0) return [];
    const first = items[0].json;
    return first?.value || (first?.id ? [first] : []);
  } catch (e) {
    return [];
  }
}

for (const u of safeGet('Check Users (All Types)')) {
  const hasLicense  = u.assignedLicenses?.length > 0;
  const isResource  = u.isResourceAccount === true;
  const isGuest     = u.userType === 'Guest';
  const isHybrid    = u.onPremisesSyncEnabled === true;
  const isDisabled  = u.accountEnabled === false;
  const purpose     = u.userPurpose?.toLowerCase();

  let accountType;
  if (purpose === 'shared')              accountType = 'Shared Mailbox';
  else if (purpose === 'room')           accountType = 'Room Mailbox';
  else if (purpose === 'equipment')      accountType = 'Equipment Mailbox';
  else if (isGuest)                      accountType = 'Guest User';
  else if (isResource && hasLicense)     accountType = 'Licensed Resource Account';
  else if (isResource)                   accountType = 'Resource Account';
  else if (isDisabled && !hasLicense)    accountType = 'Disabled Unlicensed User';
  else if (isDisabled)                   accountType = 'Disabled User';
  else if (isHybrid && hasLicense)       accountType = 'Hybrid AD User (Synced)';
  else if (isHybrid)                     accountType = 'Hybrid AD User (Unlicensed)';
  else if (hasLicense)                   accountType = 'Active Licensed User';
  else                                   accountType = 'Unlicensed User';

  addMatch({
    accountType,
    id: u.id,
    displayName: u.displayName,
    mail: u.mail,
    userPrincipalName: u.userPrincipalName,
    mailNickname: u.mailNickname,
    accountEnabled: u.accountEnabled,
    userPurpose: u.userPurpose || null,
    isResourceAccount: u.isResourceAccount,
    onPremisesSyncEnabled: u.onPremisesSyncEnabled,
    assignedLicenses: u.assignedLicenses,
    proxyAddresses: u.proxyAddresses,
    raw: u
  });
}

// ─────────────────────────────────────────────
// FINAL OUTPUT
// ─────────────────────────────────────────────
return [{
  json: {
    emailChecked: email,
    accountExists: matches.length > 0,
    matchCount: matches.length,
    accountTypes: [...new Set(matches.map(m => m.accountType))],
    matches
  }
}];

// Microsoft 365 Business Standard SKU part number
const TARGET_SKU = 'EXCHANGEENTERPRISE';

const items = $input.all();
const first = items[0]?.json;
// Handle both direct value array and nested response
const skus = Array.isArray(first?.value) ? first.value : (Array.isArray(first) ? first : []);

// Find the target SKU
const sku = skus.find(s => s.skuPartNumber === TARGET_SKU);

if (!sku) {
  return [{
    json: {
      licenseFound: false,
      licenseName: 'Exchange Online (Plan 2)',
      skuPartNumber: TARGET_SKU,
      available: false,
      availableUnits: 0,
      totalUnits: 0,
      consumedUnits: 0,
      capabilityStatus: null,
      message: 'SKU not found in tenant — license may not be purchased'
    }
  }];
}

const total    = sku.prepaidUnits?.enabled ?? 0;
const consumed = sku.consumedUnits ?? 0;
const available = total - consumed;

return [{
  json: {
    licenseFound: true,
    licenseName: 'Exchange Online (Plan 2)',
    skuPartNumber: TARGET_SKU,
    skuId: sku.skuId,
    available: available > 0,
    availableUnits: available,
    totalUnits: total,
    consumedUnits: consumed,
    capabilityStatus: sku.capabilityStatus,
    message: available > 0
      ? `${available} license(s) available`
      : 'No licenses available — all seats are consumed'
  }
}];
